module top_module(input rst,input clk,input clk_en ,input zero,output reg [14:0] eg_cnt);reg [1:0] cnt_reset_flag; 
 always @(posedge clk, posedge rst) begin : envelope_counter 
  if( rst ) begin 
  cnt_reset_flag <= 2'd0; 
  eg_cnt <=15'd0; 
  end 
  else begin 
  if( zero && clk_en ) begin 
  if( cnt_reset_flag == 2'd2 ) begin 
  eg_cnt <= eg_cnt + 1'b1; 
  cnt_reset_flag <= 2'd0; 
  end 
  else cnt_reset_flag <= cnt_reset_flag + 1'b1; 
  end 
  end 
 end 
 endmodule
